declare global {
  type JsPrimitive = string | number | boolean | bigint | symbol;
  type JsValue = object | JsPrimitive | null;

  interface String {
    trim(): string;
    toUpperCase(): string;
    includes(search: string): boolean;
  }

  interface Array<T> {
    readonly length: number;
    map<TResult>(callback: (value: T) => TResult): TResult[];
    filter(callback: (value: T) => boolean): T[];
    reduce<TResult>(
      callback: (previousValue: TResult, currentValue: T) => TResult,
      initialValue: TResult
    ): TResult;
    join(separator?: string): string;
  }

  const console: {
    log(...data: JsValue[]): void;
  };

  function parseInt(value: string): number;
}

export {};
